<template>
	<view class="preparatory-party-member-page">
		<view class="form-container">
            <form @submit.prevent="onSubmit">
				<view class="form-item">
					<label>姓名</label>
					<input v-model="formData.name" type="text" placeholder="请输入姓名" />
				</view>
				<view class="form-item">
					<label>性别</label>
					<input v-model="formData.gender" type="text" placeholder="请输入性别" />
				</view>
				<view class="form-item">
					<label>年龄</label>
					<input v-model="formData.age" type="number" placeholder="请输入年龄" />
				</view>
				<view class="form-item">
					<label>身份证号码</label>
					<input v-model="formData.identity" type="number" placeholder="请输入身份证号码" />
				</view>
                <view class="form-item">
                    <label>考察报告</label>
                    <textarea v-model="formData.report" placeholder="请输入考察报告"></textarea>
                </view>
                <view class="form-item">
                    <label>预备期</label>
                    <view style="display:flex; gap:12rpx">
                        <input v-model="formData.start" type="text" placeholder="开始时间(YYYY-MM-DD)" />
                        <input v-model="formData.end" type="text" placeholder="结束时间(YYYY-MM-DD)" />
                    </view>
                </view>
                <view class="form-item">
                    <label>附件（图片）</label>
                    <view class="upload-list">
                        <view class="upload-item" v-for="(u,i) in attachments" :key="i">
                            <image :src="u" mode="aspectFill" class="thumb" />
                            <text class="remove" @click="removeAttachment(i)">删除</text>
                        </view>
                        <button type="button" class="btn" @click="chooseImage">选择图片</button>
                    </view>
                </view>
                <button type="submit">提交预备党员申请</button>
			</form>
		</view>
	</view>
</template>

<script setup>
import { ref } from 'vue';
import { uploadAPI, applicationAPI } from '@/utils/api.js'

const formData = ref({
  name: '',
  gender:'',
  age: '',
  identity: '',
  report: '',
  start: '',
  end: ''
});

const attachments = ref([])

const chooseImage = () => {
    uni.chooseImage({
        count: 6,
        success: async (res) => {
            for (const fp of res.tempFilePaths) {
                try {
                    const { url } = await uploadAPI.uploadFile(fp)
                    attachments.value.push(url)
                } catch (e) {
                    uni.showToast({ title: '上传失败', icon: 'none' })
                }
            }
        }
    })
}

const removeAttachment = (i) => {
    attachments.value.splice(i, 1)
}

const onSubmit = async () => {
    if (!formData.value.report || !formData.value.start || !formData.value.end) {
        uni.showToast({ title: '请完善考察报告与预备期', icon: 'none' })
        return
    }
    try {
        const [resp] = await applicationAPI.applyPrepare(
            formData.value.report,
            formData.value.start + 'T00:00:00',
            formData.value.end + 'T00:00:00',
            attachments.value
        )
        if (resp.statusCode === 200 && resp.data?.code === 200) {
            uni.showToast({ title: '已提交', icon: 'success' })
            setTimeout(() => uni.navigateBack(), 800)
        } else {
            uni.showToast({ title: resp.data?.message || '提交失败', icon: 'none' })
        }
    } catch (e) {
        uni.showToast({ title: '提交失败', icon: 'none' })
    }
}

</script>

<style lang="scss" scoped>
	$primary-color: #1677ff;
	.preparatory-party-member-page {
	  padding: 20rpx;
	  background-color: #f5f5f5;
	}
	
	.form-container {
	  background-color: #fff;
	  padding: 30rpx;
	  border-radius: 12rpx;
	  box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.05);
	}
	
	.form-item {
	  margin-bottom: 20rpx;
	}
	
	.form-item label {
	  display: block;
	  margin-bottom: 10rpx;
	  font-weight: bold;
	  color: #333;
	}
	
	.form-item input,
	.form-item textarea {
	  width: 100%;
	  border: 1rpx solid #ccc;
	  border-radius: 6rpx;
	  font-size: 28rpx;
	}
	
	.form-input {
	  height: 30rpx;
	}
	
	.form-item textarea{
		padding-top: 10rpx;
	}
	
	button {
	  width: 100%;
	  height: 44px;
	  background-color: $primary-color;
	  color: #fff;
	  border-radius: 22px;
	  font-size: 16px;
	  border: none;
	  outline: none;
	  box-shadow: 0 4px 10px rgba(22, 119, 255, 0.2);
	  
	  &:active {
	    background-color: #0958d9;
	    box-shadow: 0 2px 5px rgba(22, 119, 255, 0.3);
	  }
	}
</style>
